code = """import json
file_path = locals()['var_functions.query_db:30']
with open(file_path, 'r') as f:
    articles = json.load(f)

# Look through ALL articles to find sports ones
sports_articles = []
for a in articles:
    # Check for clear sports indicators
    title = a['title'].lower()
    desc = a['description'].lower()
    full_text = title + ' ' + desc
    
    # Direct sports terms
    if any(sport in full_text for sport in ['football', 'basketball', 'baseball', 'soccer', 'tennis', 'golf', 'hockey', 'cricket']):
        sports_articles.append(a)
    # Game with clear sports context
    elif 'game' in full_text and any(indicator in full_text for indicator in ['team', 'player', 'coach', 'season', 'champion', 'league']):
        if not any(non_sport in full_text for non_sport in ['wall st', 'stock market', 'economy', 'oil prices']):
            sports_articles.append(a)

print('Articles with sports indicators:', len(sports_articles))

# Show top 10 longest sports articles
if sports_articles:
    sorted_by_length = sorted(sports_articles, key=lambda x: len(x.get('description', '')), reverse=True)
    print('\nTop 5 longest sports articles:')
    for i, article in enumerate(sorted_by_length[:5]):
        print(i+1, 'ID:', article['article_id'], 'Title:', article['title'])
        print('   Length:', len(article['description']))
        print('   Description:', article['description'][:100])
    
    longest = sorted_by_length[0]
    result = {'title': longest['title'], 'length': len(longest['description'])}
    print('\nFinal answer - Title:', longest['title'])
else:
    print('No sports articles found with indicators')
    # Let's manually search for known sports content
    for i, a in enumerate(articles[:500]):
        if 'coach' in a['title'].lower() or 'football' in a['title'].lower():
            print('Found potential sports article:', a['title'])
    print('Searching broader...')
    result = {'error': 'none found'}

print('__RESULT__:')
print(json.dumps(result))"""

